__global__ void matrix_multiply_kernel(const float *inputa, const float *inputb, float *output, int size) {
  int i = blockIdx.y * blockDim.y + threadIdx.y;
  int j = blockIdx.x * blockDim.x + threadIdx.x;

  if (i < size && j < size) {
    float sum = 0.0f;
    for (int k = 0; k < size; k++) {
      sum += inputa[i*size+k] * inputb[k*size+j];
    }
    output[i*size+j] = sum;
  }
}

void
matrix_multiply(float *inputa, float *inputb, float *output, int size){
  dim3 blockDim(16,16);
  dim3 gridDim((size + blockDim.x - 1)/blockDim.x, (size + blockDim.y - 1)/blockDim.y);

  matrix_multiply_kernel<<<gridDim, blockDim>>>(inputa, inputb, output, size);
  cudaDeviceSynchronize();
}

func_ret_t
lud_verify(float *m, float *lu, int matrix_dim){
  int i,j,k;
  float *tmp = (float*)malloc(matrix_dim*matrix_dim*sizeof(float));

  for (i=0; i < matrix_dim; i ++)
    for (j=0; j< matrix_dim; j++) {
        float sum = 0;
        float l,u;
        for (k=0; k <= MIN(i,j); k++){
            if ( i==k)
              l=1;
            else
              l=lu[i*matrix_dim+k];
            u=lu[k*matrix_dim+j];
            sum+=l*u;
        }
        tmp[i*matrix_dim+j] = sum;
    }

  for (i=0; i<matrix_dim; i++){
      for (j=0; j<matrix_dim; j++){
          if ( fabs(m[i*matrix_dim+j]-tmp[i*matrix_dim+j]) > 0.0001)
            printf("dismatch at (%d, %d): (o)%f (n)%f\n", i, j, m[i*matrix_dim+j], tmp[i*matrix_dim+j]);
      }
  }
  free(tmp);
}

