#include <stdio.h>
#include <unistd.h>
#include <getopt.h>
#include <stdlib.h>
#include <assert.h>

#include "common.h"

static int do_verify = 0;
int omp_num_threads = 40;

static struct option long_options[] = {

  {"input", 1, NULL, 'i'},
  {"size", 1, NULL, 's'},
  {"verify", 0, NULL, 'v'},
  {0,0,0,0}
};

extern void
lud_omp(float *m, int matrix_dim);

__device__ __forceinline__ float AA(const float* a, int size, int offset, int i, int j) {
    return a[offset*size + i*size + j + offset];
}

__device__ __forceinline__ void AA_set(float* a, int size, int offset, int i, int j, float val) {
    a[offset*size + i*size + j + offset] = val;
}

__device__ __forceinline__ float BB(const float* a, int size, int i, int j) {
    return a[i*size + j];
}

__device__ __forceinline__ void BB_set(float* a, int size, int i, int j, float val) {
    a[i*size + j] = val;
}

#define BS 16

__global__ void lud_diagonal_kernel(float* a, int size, int offset) {
    int i = threadIdx.x;
    if (i >= BS) return;

    for (int j = i; j < BS; j++) {
        float val = AA(a, size, offset, i, j);
        for (int k = 0; k < i; k++) {
            val -= AA(a, size, offset, i, k) * AA(a, size, offset, k, j);
        }
        AA_set(a, size, offset, i, j, val);
    }
    __syncthreads();

    float temp = 1.f / AA(a, size, offset, i, i);
    for (int j = i + 1; j < BS; j++) {
        float val = AA(a, size, offset, j, i);
        for (int k = 0; k < i; k++) {
            val -= AA(a, size, offset, j, k) * AA(a, size, offset, k, i);
        }
        val = val * temp;
        AA_set(a, size, offset, j, i, val);
    }
}

__global__ void lud_internal_row_kernel(float* a, int size, int offset, int chunks_in_inter_row) {
    int chunk_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (chunk_idx >= chunks_in_inter_row) return;

    float temp[BS*BS];
    int i, j, k;
    int i_global = offset;
    int j_global = offset;

    // Load temp matrix
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            temp[i*BS + j] = a[size*(i + offset) + offset + j];
        }
    }

    j_global += BS * (chunk_idx + 1);
    for (j = 0; j < BS; j++) {
        for (i = 0; i < BS; i++) {
            float sum = 0.f;
            for (k = 0; k < i; k++) {
                sum += temp[BS*i + k] * BB(a, size, i_global + k, j_global + j);
            }
            int i_here = i_global + i;
            int j_here = j_global + j;
            BB_set(a, size, i_here, j_here, BB(a, size, i_here, j_here) - sum);
        }
    }

    j_global = offset;
    i_global += BS * (chunk_idx + 1);
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            float sum = 0.f;
            for (k = 0; k < j; k++) {
                sum += BB(a, size, i_global + i, j_global + k) * temp[BS*k + j];
            }
            int i_here = i_global + i;
            int j_here = j_global + j;
            float val = a[size*i_here + j_here];
            val = (val - sum) / a[size*(offset + j) + offset + j];
            a[size*i_here + j_here] = val;
        }
    }
}

__global__ void lud_internal_diag_kernel(float* a, int size, int offset, int chunks_in_inter_row) {
    int chunk_idx = blockIdx.x * blockDim.x + threadIdx.x;
    int chunks_per_inter = chunks_in_inter_row * chunks_in_inter_row;
    if (chunk_idx >= chunks_per_inter) return;

    float temp_top[BS*BS];
    float temp_left[BS*BS];
    float sum[BS] = {0.f};

    int i_global = offset + BS * (1 + chunk_idx / chunks_in_inter_row);
    int j_global = offset + BS * (1 + chunk_idx % chunks_in_inter_row);

    int i, j, k;

    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            temp_top[i*BS + j] = a[size*(i + offset) + j + j_global];
            temp_left[i*BS + j] = a[size*(i + i_global) + offset + j];
        }
    }

    for (i = 0; i < BS; i++) {
        for (k = 0; k < BS; k++) {
            for (j = 0; j < BS; j++) {
                sum[j] += temp_left[BS*i + k] * temp_top[BS*k + j];
            }
        }
        for (j = 0; j < BS; j++) {
            int row = i + i_global;
            int col = j + j_global;
            a[size*row + col] -= sum[j];
            sum[j] = 0.f;
        }
    }
}

void lud_omp(float *a, int size)
{
    int offset;

    for (offset = 0; offset < size - BS ; offset += BS)
    {
        // Launch diagonal kernel with BS threads
        lud_diagonal_kernel<<<1, BS>>>(a, size, offset);
        cudaDeviceSynchronize();

        int size_inter = size - offset - BS;
        int chunks_in_inter_row = size_inter / BS;

        if (chunks_in_inter_row > 0) {
            int threads = 256;
            int blocks = (chunks_in_inter_row + threads - 1) / threads;
            lud_internal_row_kernel<<<blocks, threads>>>(a, size, offset, chunks_in_inter_row);
            cudaDeviceSynchronize();

            int chunks_per_inter = chunks_in_inter_row * chunks_in_inter_row;
            blocks = (chunks_per_inter + threads - 1) / threads;
            lud_internal_diag_kernel<<<blocks, threads>>>(a, size, offset, chunks_in_inter_row);
            cudaDeviceSynchronize();
        }
    }

    // Final diagonal block
    lud_diagonal_kernel<<<1, BS>>>(a, size, offset);
    cudaDeviceSynchronize();
}

int main ( int argc, char *argv[] )
{
  int matrix_dim = 32; 
  int opt, option_index=0;
  func_ret_t ret;
  const char *input_file = NULL;
  float *m, *mm;
  stopwatch sw;


  while ((opt = getopt_long(argc, argv, "::vs:n:i:", 
                            long_options, &option_index)) != -1 ) {
    switch(opt){
    case 'i':
      input_file = optarg;
      break;
    case 'v':
      do_verify = 1;
      break;
    case 'n':
      omp_num_threads = atoi(optarg);
      break;
    case 's':
      matrix_dim = atoi(optarg);
      printf("Generate input matrix internally, size =%d\n", matrix_dim);



      break;
    case '?':
      fprintf(stderr, "invalid option\n");
      break;
    case ':':
      fprintf(stderr, "missing argument\n");
      break;
    default:
      fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
	      argv[0]);
      exit(EXIT_FAILURE);
    }
  }

  if ( (optind < argc) || (optind == 1)) {
    fprintf(stderr, "Usage: %s [-v] [-n no. of threads] [-s matrix_size|-i input_file]\n", argv[0]);
    exit(EXIT_FAILURE);
  }

  if (input_file) {
    printf("Reading matrix from file %s\n", input_file);
    ret = create_matrix_from_file(&m, input_file, &matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix from file %s\n", input_file);
      exit(EXIT_FAILURE);
    }
  }
  else if (matrix_dim) {
    printf("Creating matrix internally size=%d\n", matrix_dim);
    ret = create_matrix(&m, matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix internally size=%d\n", matrix_dim);
      exit(EXIT_FAILURE);
    }
  }

  else {
    printf("No input file specified!\n");
    exit(EXIT_FAILURE);
  } 

  if (do_verify){
    printf("Before LUD\n");

    matrix_duplicate(m, &mm, matrix_dim);
  }


  stopwatch_start(&sw);
  lud_omp(m, matrix_dim);
  stopwatch_stop(&sw);
  printf("Time consumed(ms): %lf\n", 1000*get_interval_by_sec(&sw));

  if (do_verify){
    printf("After LUD\n");

    printf(">>>Verify<<<<\n");
    lud_verify(mm, m, matrix_dim); 
    free(mm);
  }

  free(m);

  return EXIT_SUCCESS;
}
